window.__QUIZ_DATA__=[{"id":"objective>Commerce>1997>1","subject":"Commerce","year":"1997","type":"Objective","topic":"OCCUPATION : TYPES OF OCCUPATION","question":"Extractive occupation is an example of","images":[],"options":{"A":"construction industry","B":"manufacturing industry","C":"tertiary industry","D":"primary industry"},"answer":"D","explanation":"Extractive occupations are those that involve the extraction of raw materials from the earth. This includes activities such as mining, fishing, lumbering, and farming. These occupations fall under the primary industry, which is concerned with the extraction of raw materials. Therefore, the correct answer is 'primary industry'.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1997>2","subject":"Commerce","year":"1997","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : TYPES","question":"The fastest means of sending a printed message from Lagos to London is through","images":[],"options":{"A":"aeroplane","B":"telephone","C":"cablegram","D":"telex"},"answer":"D","explanation":"The fastest means of sending a printed message from Lagos to London would be through telex. Telex is a networked system of teleprinters, which can send and receive text-based messages instantly. While an aeroplane can physically transport a printed message, it is not as fast as electronic transmission. A telephone is used for voice communication, not printed messages. A cablegram is a dated term for a telegram sent by submarine cable, which is also not as fast as telex.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>3","subject":"Commerce","year":"1997","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE","question":"An association that mobilizes the savings of members and channels them to needy members is known as","images":[],"options":{"A":"Consumer Co-operative","B":"Producer Co-operative","C":"Thrift and Credit Co-operative","D":"Multi-purpose Co-operative"},"answer":"C","explanation":"A Thrift and Credit Co-operative is a type of co-operative that mobilizes the savings of its members and channels them to needy members. This is done through loans and other forms of financial assistance. The other options do not accurately describe this type of co-operative.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>4","subject":"Commerce","year":"1997","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"If Ade issues a Union Bank cheque to Chukwu, the Union Bank is the","images":[],"options":{"A":"drawee","B":"payee","C":"drawer","D":"acceptor"},"answer":"A","explanation":"In the context of a cheque, the drawee is the bank or other financial institution that is asked to pay the amount. In this case, Union Bank is the drawee because it is the bank that is asked to pay the amount of the cheque to Chukwu. The drawer is the person who writes the cheque (in this case, Ade), and the payee is the person to whom the cheque is made out (in this case, Chukwu). The acceptor is not a term used in the context of a cheque.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>5","subject":"Commerce","year":"1997","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"Which of the following is the clearing house for all the banks in the country?","images":[],"options":{"A":"The Federal Mortgage Bank of Nigeria","B":"The Nigerian Industrial Development Bank","C":"The Central Bank of Nigeria","D":"The Nigerian Bank for Commerce and Industry"},"answer":"C","explanation":"The Central Bank of Nigeria serves as the clearing house for all the banks in the country. A clearing house is a financial institution formed to facilitate the exchange (i.e., clearance) of payments, securities, or derivatives transactions. The Central Bank of Nigeria provides this service for all other banks in the country.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1997>6","subject":"Commerce","year":"1997","type":"Objective","topic":"INTRODUCTION TO COMMERCE : CHARACTERISTICS & FUNCTIONS","question":"Commerce developed as a result of","images":[],"options":{"A":"speculation","B":"competition","C":"specialization","D":"importation"},"answer":"C","explanation":"Commerce developed as a result of specialization. Specialization refers to the method of production where a business, area or economy focuses on the production of a limited scope of products or services to gain greater degrees of productive efficiency within an overall system. This leads to trade as people exchange the goods and services that they specialize in for other goods and services they need, hence leading to the development of commerce.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1997>7","subject":"Commerce","year":"1997","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"An overdraft can only be granted to the holder of a","images":[],"options":{"A":"fixed deposit","B":"savings deposit","C":"loan account","D":"current account"},"answer":"D","explanation":"An overdraft is a facility provided by banks to their customers (usually businesses) to withdraw more money from their account than what is actually available. This facility is typically provided only to current account holders. A current account is a type of deposit account that caters to professionals and businessmen alike. Dealing largely with liquid deposits, this product allows for withdrawal of funds and checks being written against the balance and does not limit the number of transactions in a day.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>8","subject":"Commerce","year":"1997","type":"Objective","topic":"OCCUPATION : MEANING & IMPORTANCE","question":"Use the diagram below to answer the questions         The appropriate label for X on the diagram is","images":["data:image/png;base64,"],"options":{"A":"commerce","B":"industry","C":"direct services","D":"occupations"},"answer":"A","explanation":"X on the diagram represent commerce which is divided into trade and aids to trade.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1997>9","subject":"Commerce","year":"1997","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : TYPES","question":"Use the diagram below to answer the questions       The appropriate label for Y on the diagram is","images":["data:image/png;base64,"],"options":{"A":"branches of commerce","B":"distribution channel","C":"direct services","D":"aids to trade"},"answer":"D","explanation":"Y on the diagram represent Aids to trade. Aids to trade helps to facilitate trade and it includes: banking, transportation, communication, insurance, warehousing, etc.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1997>10","subject":"Commerce","year":"1997","type":"Objective","topic":"TRADE : HOME TRADE: WHOLESALE TRADE","question":"Use the diagram below to answer the questions       The appropriate label for P on the diagram is","images":["data:image/png;base64,"],"options":{"A":"home trade","B":"agent","C":"wholesale","D":"co-operatives"},"answer":"C","explanation":"P represent Wholesale Trade. The wholesale trade is a type of trade in which goods are sold to the retailer in large quantities.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1997>11","subject":"Commerce","year":"1997","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE","question":"Which of the following is not a source of capital to a partnership?","images":[],"options":{"A":"Buying on credit","B":"Ploughed back profit","C":"Borrowing","D":"Shares"},"answer":"D","explanation":"A partnership is a type of business where two or more people share ownership, as well as the risk of loss and the potential for profit. The sources of capital for a partnership can include buying on credit, ploughed back profit, and borrowing. However, shares are not a source of capital for a partnership. Shares are typically associated with corporations, where the business is owned by shareholders. In a partnership, the partners contribute capital and share in the profits and losses.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>12","subject":"Commerce","year":"1997","type":"Objective","topic":"TRADE : HOME TRADE: WHOLESALE TRADE","question":"Which of the following functions of the wholesaler helps to stabilize prices","images":[],"options":{"A":"Financing","B":"Advice to retailers","C":"Provision of credit","D":"Warehousing"},"answer":"D","explanation":"The function of the wholesaler that helps to stabilize prices is Warehousing. Warehousing involves the storage of goods. By storing goods, wholesalers can release them into the market when there is demand, thus preventing a surplus or shortage of goods which can lead to price instability.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>13","subject":"Commerce","year":"1997","type":"Objective","topic":"TRADE : HOME TRADE: WHOLESALE TRADE","question":"The rebate given to the retailer by the wholesaler to enable him make profit is known as","images":[],"options":{"A":"commission","B":"mark-up","C":"trade discount","D":"cash discount"},"answer":"C","explanation":"The rebate given to the retailer by the wholesaler to enable him make profit is known as trade discount. A trade discount is a reduction in the listed price of an item when it's sold for resale. It's used as an incentive for the retailer to carry and promote a wholesaler's product.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>14","subject":"Commerce","year":"1997","type":"Objective","topic":"PRODUCTION : DIVISION OF LABOUR & SPECIALISATION","question":"Division of labour often results in","images":[],"options":{"A":"a decrease in production","B":"an increase in production","C":"waste of time","D":"uneconomic use of tools"},"answer":"B","explanation":"Division of labour refers to the breaking down of a production process into small tasks, with each task performed by a specialist. It often results in an increase in production because it allows workers to focus on a few tasks, thereby improving their efficiency and productivity.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1997>15","subject":"Commerce","year":"1997","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT","question":"Who among the following is not an agent?","images":[],"options":{"A":"Broker","B":"Factor","C":"Jobber","D":"Manufacturer's representative"},"answer":"C","explanation":"In commerce, an agent is a person or entity that has been legally empowered to act on behalf of another person or entity. A broker, factor, and manufacturer's representative are all types of agents as they act on behalf of others in commercial transactions. However, a jobber is not an agent. A jobber is a trader who purchases goods from manufacturers and sells them to retailers or consumers. Unlike agents, jobbers take ownership of the goods they deal in.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1997>16","subject":"Commerce","year":"1997","type":"Objective","topic":"ELEMENT OF MARKETING : MARKETING MIX","question":"Who among the following comes first in the channel of distribution?","images":[],"options":{"A":"Consumer","B":"Retailer","C":"Consignor","D":"Manufacturer"},"answer":"D","explanation":"In the channel of distribution, the manufacturer comes first. The manufacturer is the one who produces the goods. After production, the goods are then passed on to the wholesaler, then to the retailer, and finally to the consumer. So, the correct answer is Manufacturer.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>17","subject":"Commerce","year":"1997","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"The services rendered by Nigerian Airways to foreign companies are part of Nigeria's","images":[],"options":{"A":"visible exports","B":"visible imports","C":"invisible exports","D":"invisible imports"},"answer":"C","explanation":"The services rendered by Nigerian Airways to foreign companies are part of Nigeria's invisible exports. Invisible exports refer to the sale of services to foreign countries. These services can include transportation, tourism, banking, and insurance services. In this case, the services provided by Nigerian Airways to foreign companies are considered as an export of services from Nigeria to other countries, hence they are termed as invisible exports.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>18","subject":"Commerce","year":"1997","type":"Objective","topic":"STOCK EXCHANGE : TYPES OF SECURITIES","question":"One of the characteristics of a debenture is that","images":[],"options":{"A":"it yields a fixed rate of dividends","B":"it has no redemption date","C":"it yields a fixed rate of interest","D":"its holder has a voting right"},"answer":"C","explanation":"A debenture is a type of debt instrument that is not secured by physical assets or collateral. Debentures are backed only by the general creditworthiness and reputation of the issuer. One of the characteristics of a debenture is that it yields a fixed rate of interest, not dividends. Therefore, the correct answer is 'it yields a fixed rate of interest'.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1997>19","subject":"Commerce","year":"1997","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : ADVANTAGES & DISADVANTAGES","question":"Which of the following is a disadvantage of credit transaction?","images":[],"options":{"A":"increases turnover","B":"facilitates the sale of durable goods","C":"encourages the habit of saving","D":"encourages bad debt"},"answer":"D","explanation":"Credit transaction refers to a transaction where the goods are sold and delivered, but the payment is made at a later date. While it has several advantages like increasing turnover and facilitating the sale of durable goods, one of the disadvantages is that it can encourage bad debt. Bad debt is money that is owed to a company and is unlikely to be paid. Therefore, the correct answer is 'encourages bad debt'.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>20","subject":"Commerce","year":"1997","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: HIRE PURCHASES : MEANING AND TYPES","question":"In which of the following do the goods become the property of the buyer on the payment of first installment","images":[],"options":{"A":"Hire-purchase","B":"Deferred payment","C":"Leasehold","D":"Cash with order"},"answer":"A","explanation":"In a hire-purchase agreement, the goods become the property of the buyer after the payment of the first installment. This is because the hire-purchase agreement is a type of installment plan where the buyer takes possession of the items immediately but ownership of the goods is transferred only when the full payment has been completed.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>21","subject":"Commerce","year":"1997","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION","question":"Which of the following government legislation is not aimed at consumer protection?","images":[],"options":{"A":"Taxation Law","B":"Sales of Goods Act","C":"Food and Drugs Act","D":"Standards Organization Act"},"answer":"A","explanation":"Taxation Law is not aimed at consumer protection. It is a body of laws and rules which govern the process of government levying taxes on citizens and businesses. The other options like Sales of Goods Act, Food and Drugs Act, and Standards Organization Act are all aimed at protecting the rights and interests of consumers.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>22","subject":"Commerce","year":"1997","type":"Objective","topic":"ELEMENT OF MARKETING : MARKETING MIX","question":"Self-service, mail order and automatic vending are examples of","images":[],"options":{"A":"marketing mix","B":"sales promotion","C":"public relations","D":"selling techniques"},"answer":"D","explanation":"Self-service, mail order, and automatic vending are examples of selling techniques. Selling techniques are strategies that companies use to promote and sell their products or services. These techniques can vary depending on the nature of the product or service, the target audience, and other factors. In this case, self-service, mail order, and automatic vending are all methods that allow customers to purchase products or services without the need for a salesperson or other intermediary.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1997>23","subject":"Commerce","year":"1997","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE","question":"Span of control is defined as the","images":[],"options":{"A":"authority of the supervisor","B":"qualification possessed by the supervisor","C":"number of staff in the organization","D":"number of subordinates reporting directly to a supervisor"},"answer":"D","explanation":"Span of control refers to the number of subordinates that a manager or supervisor can effectively manage. This can vary depending on the nature of the work, the skills of the manager or supervisor, and the skills of the subordinates. In this case, the span of control is defined as the number of subordinates reporting directly to a supervisor.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>24","subject":"Commerce","year":"1997","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE","question":"An established pattern of relationships among members of an organization is known as","images":[],"options":{"A":"organizational behaviour","B":"organizational structure","C":"organizational manual","D":"organizational climate"},"answer":"B","explanation":"An established pattern of relationships among members of an organization is known as organizational structure. Organizational structure refers to how individual and team work within an organization are coordinated. It defines how tasks are divided, grouped, and coordinated in an organization.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>25","subject":"Commerce","year":"1997","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE","question":"The aspect of management which ensures that there is no deviation from the set standards is called","images":[],"options":{"A":"controlling","B":"planning","C":"commanding","D":"organizing"},"answer":"A","explanation":"The aspect of management which ensures that there is no deviation from the set standards is called controlling. Controlling is the process of comparing actual performance with the set standards of the organization's goals and then taking corrective action as necessary. It's a fundamental aspect of management that allows an organization to track performance and ensure that necessary changes are made in a timely manner.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>26","subject":"Commerce","year":"1997","type":"Objective","topic":"BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES","question":"When a Public Limited Company is incorporated it means that","images":[],"options":{"A":"it is entitled to commence business","B":"It has been given certificate of trading","C":"It has a legal existence","D":"its shares cannot be transferred"},"answer":"C","explanation":"Incorporation of a Public Limited Company means that it has a legal existence separate from its owners. It can own property, sue and be sued in its own name. This is a concept known as 'corporate personality'.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1997>27","subject":"Commerce","year":"1997","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"The Manager,  Afribank,  Lagos.    Please pay to Great Nigeria Insurance Company, from my account, a sum of #125.00 at the end of every month until further notice, starting from this month.    The above instruction is a","images":[],"options":{"A":"bill of exchange","B":"certified cheque","C":"promissory note","D":"standing order"},"answer":"D","explanation":"The instruction given in the question is a standing order. A standing order is an instruction a bank account holder gives to their bank to pay a set amount at regular intervals to another's account. The other options do not fit the description given in the question. A bill of exchange is a written order used primarily in international trade that binds one party to pay a fixed sum of money to another party at a predetermined future date. A certified cheque is a type of cheque for which the bank verifies that sufficient funds exist in the account to cover the cheque, and so it cannot be bounced. A promissory note is a financial instrument that contains a written promise by one party to pay another party a definite sum of money either on demand or at a specified future date.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>28","subject":"Commerce","year":"1997","type":"Objective","topic":"TRADE : HOME TRADE: RETAIL TRADE","question":"A retailer's mark-up is his","images":[],"options":{"A":"total cost less total sales","B":"total sales less total returns","C":"gross profit less expenses","D":"selling price less cost price"},"answer":"D","explanation":"A retailer's mark-up is the difference between the cost of a good or service and its selling price. It is calculated by subtracting the cost price from the selling price. This is the retailer's gross profit before any expenses are deducted.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>29","subject":"Commerce","year":"1997","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE","question":"Debenture is an example of","images":[],"options":{"A":"fixed capital","B":"share capital","C":"loan capital","D":"working capital"},"answer":"C","explanation":"A debenture is a type of debt instrument that is not secured by physical assets or collateral. It is an example of loan capital, which is a form of long-term debt. Debentures are backed only by the general creditworthiness and reputation of the issuer. Fixed capital refers to any kind of real or physical capital (fixed asset) that is not used up in the production of a product, share capital refers to all funds raised by a company in exchange for shares of either common or preferred shares of stock, and working capital is a measure of both a company's operational efficiency and its short-term financial health.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>30","subject":"Commerce","year":"1997","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"Which of the following is not an acceptable collateral security for a bank loan?","images":[],"options":{"A":"Certificate of occupancy","B":"Life assurance policy","C":"Lien on deposit account","D":"Warehouse warrant"},"answer":"B","explanation":"A life assurance policy is not an acceptable collateral security for a bank loan. Collateral is something pledged as security for repayment of a loan, to be forfeited in the event of a default. A life assurance policy does not meet this criteria as it is a contract with an insurance company. In exchange for premium payments, the insurance company provides a lump-sum payment, known as a death benefit, to beneficiaries upon the insured's death. It does not have a guaranteed value that can be used as collateral.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1997>31","subject":"Commerce","year":"1997","type":"Objective","topic":"ELEMENT OF MARKETING : THE MARKETING CONCEPT","question":"Which of the following is the basic principle of marketing concept?","images":[],"options":{"A":"Seller-oriented","B":"Producer-oriented","C":"Consumer-oriented","D":"Manufacturer-oriented"},"answer":"C","explanation":"The basic principle of marketing concept is being consumer-oriented. This means that the company focuses on meeting the needs and wants of the consumers rather than just focusing on the product or the producer. The company designs its marketing strategy around what the consumer needs or wants, and not just on what the company wants to sell.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>32","subject":"Commerce","year":"1997","type":"Objective","topic":"STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS","question":"The compensation given to brokers who sell shares to jobbers is called","images":[],"options":{"A":"premium","B":"commission","C":"salary","D":"interest"},"answer":"B","explanation":"The compensation given to brokers who sell shares to jobbers is called commission. In the stock market, a commission is a service charge assessed by a broker or investment advisor in return for providing investment advice and/or handling the purchase or sale of a security.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>33","subject":"Commerce","year":"1997","type":"Objective","topic":"STOCK EXCHANGE : TYPES OF SECURITIES","question":"The Stock Exchange does not deal in","images":[],"options":{"A":"shares","B":"treasury bills","C":"debentures","D":"stocks"},"answer":"B","explanation":"The Stock Exchange does not deal in treasury bills. Treasury bills are short-term debt obligations issued by a national government to finance their spending. They are not traded in the stock exchange but in the money market.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>34","subject":"Commerce","year":"1997","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : PRINCIPLES","question":"The insurance principle which expects the insured and the insurer to disclose all facts about a proposed contract is called","images":[],"options":{"A":"uberrimae fidei","B":"indemnity","C":"proximate cause","D":"insurable interest"},"answer":"A","explanation":"The principle of 'uberrimae fidei' or utmost good faith is a fundamental principle of insurance. According to this principle, the insurance contract must be signed by both parties (i.e., the insurer and the insured) in an absolute good faith or belief or trust. The person getting insured must willingly disclose and surrender to the insurer his complete true information regarding the subject matter of insurance. The insurer's liability gets void (i.e., legally revoked or cancelled) if any facts, about the subject matter of insurance are either omitted, hidden, falsified or presented in a wrong manner.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1997>35","subject":"Commerce","year":"1997","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TYPES","question":"Which of the following is not covered by fire insurance policy?","images":[],"options":{"A":"Consequential loss","B":"Gas explosion","C":"Domestic boilers","D":"Lightning"},"answer":"A","explanation":"Fire insurance policies typically do not cover consequential losses. Consequential loss is an indirect loss, which is not caused directly by the insured peril, but is the result of another loss, which is directly caused by the insured peril. For example, if a fire occurs and a business must close for repairs, the loss of income during the closure would be considered a consequential loss.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1997>36","subject":"Commerce","year":"1997","type":"Objective","topic":"TRADE : HOME TRADE: RETAIL TRADE","question":"Which of the following is not considered when siting a retail shop?","images":[],"options":{"A":"Advertising","B":"Rent","C":"Accessibility","D":"Target population"},"answer":"A","explanation":"When siting a retail shop, factors such as rent, accessibility, and target population are considered. Rent is important because it determines the cost of maintaining the shop at that location. Accessibility is crucial because it determines how easy it is for customers to reach the shop. The target population is also considered because it determines the potential customer base. However, advertising is not a factor considered when siting a retail shop. Advertising is a strategy used to promote the shop and its products after it has been established.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>37","subject":"Commerce","year":"1997","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION","question":"The law stipulating that labels should contain full details about a product is known as the","images":[],"options":{"A":"Hire-purchase Act","B":"Price Control Act","C":"Standards Organisation of Nigeria Act","D":"Trade description Act"},"answer":"D","explanation":"The Trade Description Act is the law that stipulates that labels should contain full details about a product. This law is designed to prevent manufacturers, retailers or service industry providers from misleading consumers as to what they are spending their money on. This can include information about the product, how it works, what it contains, and any other relevant information. The other options, Hire-purchase Act, Price Control Act, and Standards Organisation of Nigeria Act, do not specifically deal with product labeling.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1997>38","subject":"Commerce","year":"1997","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : MEANING AND TYPES","question":"A design which distinguishes the goods of one producer from those of others is called","images":[],"options":{"A":"patent-right","B":"copyright","C":"trade mark","D":"licence"},"answer":"C","explanation":"A design which distinguishes the goods of one producer from those of others is called a trade mark. A trademark is a recognizable sign, design, or expression which identifies products or services of a particular source from those of others. It is a type of intellectual property consisting of a recognizable sign, design, or expression which distinguishes products or services of a particular source from those of others.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>39","subject":"Commerce","year":"1997","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : REGULATORY AGENCIES","question":"Which of the following is responsible for the maintenance of the quality of goods produced","images":[],"options":{"A":"Customs and Exercise Department","B":"Sanitary Inspectors","C":"Standards Organization of Nigeria","D":"Federal Environmental Protection Agency"},"answer":"C","explanation":"The Standards Organization of Nigeria is responsible for the maintenance of the quality of goods produced. It is the apex standardization body in Nigeria. It was established to ensure that goods and services produced or imported into Nigeria meet the minimum requirements of Nigerian Industrial Standards (NIS), and are safe and fit for their intended uses.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>40","subject":"Commerce","year":"1997","type":"Objective","topic":"TRADE : DOCUMENT USED IN INTERNATIONAL TRADE","question":"The document stating the particular country from which goods are imported is called","images":[],"options":{"A":"certificate of origin","B":"export invoice","C":"consular invoice","D":"export licence"},"answer":"A","explanation":"A Certificate of Origin (CoO) is a document that states the country of origin of a particular product. It is used in international trade and is important because it helps to determine whether certain goods are eligible for import, or whether goods are subject to duties. It is usually issued by a Chamber of Commerce and contains information like the exporter, the importer, and a description of the goods.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>41","subject":"Commerce","year":"1997","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : TYPES","question":"Which of the following makes it possible for people to collect their letters at their convenient time ?","images":[],"options":{"A":"Franking","B":"Record Delivery","C":"Post Office Box","D":"Business Reply Service"},"answer":"C","explanation":"A Post Office Box (P.O. Box) is a uniquely addressable lockable box located on the premises of a post office station. It allows people to receive mail at a place other than their home. This makes it possible for people to collect their letters at their convenient time as the mail is securely stored in the box until it is collected by the owner.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1997>42","subject":"Commerce","year":"1997","type":"Objective","topic":"TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.","question":"Which of the following is not a function of the Nigerian Ports Authority?","images":[],"options":{"A":"Checking smuggling activities","B":"Handling of goods","C":"Collection of harbour dues","D":"Decongestion of ports"},"answer":"A","explanation":"The function of checking smuggling activities is not a direct function of the Nigerian Ports Authority. This function is primarily carried out by the Nigerian Customs Service. The Nigerian Ports Authority is responsible for the administration of the ports, handling of goods, collection of harbour dues, and decongestion of ports.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>43","subject":"Commerce","year":"1997","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"Which of the following indicates special crossing on a cheque? Two parallel lines with","images":[],"options":{"A":"\"& Co\" and \"not negotiable\"","B":"the abbreviation \"& Co\" only","C":"\"account payee\" only","D":"the name of a particular bank"},"answer":"C","explanation":"In special crossing, the name of a bank is inserted between the transerve lines. This restricts payment to a specific named bank. The forms special crossing are:   - non negotiable: cheque cannot be paid to any person except the bearer of the name on the cheque. e.g \"& Co\" or \" Non-negotiable\" etc.  - Alc payee only: the cheques are to be paid into the account of the person or firm named on the cheque.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>44","subject":"Commerce","year":"1997","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING","question":"Which of the following is usually sent to prospective buyer when the seller expects payment of the goods dispatched?","images":[],"options":{"A":"Pro-forma invoice","B":"Advice note","C":"Consignment note","D":"Statement of account"},"answer":"A","explanation":"A Pro-forma invoice is a preliminary bill of sale sent to buyers in advance of a shipment or delivery of goods. It is usually sent when the seller expects payment for the goods dispatched. It typically describes the purchased items and notes the cost along with other important information like shipping weight and transport charges.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>45","subject":"Commerce","year":"1997","type":"Objective","topic":"BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER","question":"A company which acquires more than 50% voting shares of another company is called?","images":[],"options":{"A":"a trust","B":"a cartel","C":"a holding company","D":"a consortium"},"answer":"C","explanation":"A holding company is a company that owns the stocks of other companies. The term is usually used to refer to a company that does not produce goods or services itself, but its purpose is to own shares of other companies. If a company acquires more than 50% voting shares of another company, it is called a holding company because it has controlling interest in the company.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1997>46","subject":"Commerce","year":"1997","type":"Objective","topic":"BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER","question":"Which of the following is true of a merger?","images":[],"options":{"A":"Original names of the companies are retained","B":"Expansion is restricted","C":"All debts are written off","D":"The company formed acquires a new name"},"answer":"D","explanation":"A merger is a business strategy of combining two or more companies into a single company. In most cases, the merged companies acquire a new name to represent the new entity formed. This is done to create a new corporate identity. Therefore, the statement 'The company formed acquires a new name' is true of a merger.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1997>47","subject":"Commerce","year":"1997","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TYPES","question":"Which of the following covers damages to the body of a ship and its machinery?","images":[],"options":{"A":"Freight insurance","B":"Cargo insurance","C":"General average insurance","D":"Hull insurance"},"answer":"D","explanation":"Hull insurance is a type of marine insurance that covers damages to the body of a ship and its machinery. It is designed to provide coverage for physical damages to the ship, including the hull and machinery. Therefore, the statement 'Hull insurance covers damages to the body of a ship and its machinery' is correct.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>48","subject":"Commerce","year":"1997","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION","question":"The major disadvantage of pipeline transportation is that it","images":[],"options":{"A":"does not involve too much labour","B":"reduces road congestion","C":"is fast","D":"is not easy to detect damages"},"answer":"D","explanation":"The major disadvantage of pipeline transportation is that it is not easy to detect damages. This is because pipelines are often buried underground or under the sea, making it difficult to visually inspect them for damages. This can lead to undetected leaks or ruptures, which can cause significant environmental damage and financial loss.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1997>49","subject":"Commerce","year":"1997","type":"Objective","topic":"TRADE : DOCUMENT USED IN INTERNATIONAL TRADE","question":"Which of the following are true of a bill of lading?     i. it is a means of payment in foreign trade.   ii. it is document of title to goods.   iii. it is a contract of carriage.   iv. it is usually drawn in triplicate.","images":[],"options":{"A":"i and iii only","B":"i, ii and iii only","C":"ii and iii only","D":"ii, iii and iv only"},"answer":"D","explanation":"A bill of lading is a document used in trade to detail the goods being transported, the destination, and the party responsible for the shipment. It serves as a contract of carriage, a document of title to goods, and is usually drawn in triplicate. However, it is not a means of payment in foreign trade. Therefore, the statements ii, iii, and iv are correct.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1997>50","subject":"Commerce","year":"1997","type":"Objective","topic":"TRADE : BALANCE OF PAYMENT","question":"The difference between the total amount owed to a country and the total amount owed by it is","images":[],"options":{"A":"trade surplus","B":"terms of trade","C":"balance of payments","D":"balance of trade"},"answer":"D","explanation":"The difference between the total amount owed to a country and the total amount owed by it is referred to as the balance of trade. The balance of trade is the difference between the value of a country's exports and the value of its imports. If a country exports more than it imports, it has a trade surplus. If it imports more than it exports, it has a trade deficit. The balance of trade is a significant part of a country's balance of payments, which includes all transactions between a country's residents and its nonresidents.","marks":"1","difficulty":"2"}];